// Input from caller: positions, watchlist (stocks, crypto)
const input = $input.first().json;

const positions = input.positions || {};
const watchlistStocks = input.watchlist?.stocks || ['NVDA', 'MSFT', 'GOOGL', 'AAPL', 'VOO', 'META', 'AMZN'];
const watchlistCrypto = input.watchlist?.crypto || ['ethereum', 'solana'];

// Combine positions with watchlist
const positionSymbols = Object.values(positions).map(p => p.symbol?.toUpperCase()).filter(Boolean);
const allStocks = [...new Set([...positionSymbols.filter(s => {
  const pos = Object.values(positions).find(p => p.symbol?.toUpperCase() === s);
  return pos?.asset_type === 'stock';
}), ...watchlistStocks])];
const allCrypto = [...new Set([...positionSymbols.filter(s => {
  const pos = Object.values(positions).find(p => p.symbol?.toUpperCase() === s);
  return pos?.asset_type === 'crypto';
}).map(s => s.toLowerCase()), ...watchlistCrypto])];

return [{
  json: {
    positions,
    stocks: allStocks,
    crypto: allCrypto,
    timestamp: new Date().toISOString(),
    timeLabel: new Date().getHours() < 12 ? 'morning' : 'afternoon'
  }
}];

// Enhanced Parse Stocks with ALL technical indicators
const items = $input.all();
const symbols = $('Split Stocks').all();
const results = [];

// Load optimized parameters
let optimizedParams = {
  rsi_period: 14,
  rsi_oversold: 30,
  rsi_overbought: 70,
  bb_std_dev: 2.0,
  volume_threshold: 1.5,
  macd_fast: 12,
  macd_slow: 26,
  macd_signal: 9
};

try {
  const paramsData = $input.first().json?.optimized_params;
  if (paramsData) {
    optimizedParams = { ...optimizedParams, ...paramsData };
  }
} catch (e) {}

for (let i = 0; i < items.length; i++) {
  try {
    if (items[i].json.error || items[i].json.code) {
      console.log('API error for', symbols[i]?.json?.symbol, ':', items[i].json.message || 'Unknown error');
      continue;
    }

    const data = items[i].json.chart?.result?.[0];
    const symbol = symbols[i]?.json?.symbol;
    if (!data || !symbol) continue;

    const quote = data.indicators?.quote?.[0];
    const closes = (quote?.close || []).filter(c => c != null);
    const highs = (quote?.high || []).filter(h => h != null);
    const lows = (quote?.low || []).filter(l => l != null);
    const volumes = (quote?.volume || []).filter(v => v != null);

    if (closes.length < 30) {
      console.log('Insufficient data for:', symbol);
      continue;
    }

    const price = closes[closes.length - 1];
    const high30 = Math.max(...closes.slice(-30));
    const low30 = Math.min(...closes.slice(-30));

    // RSI variants (7, 14, 21)
    function calcRSI(prices, period) {
      if (prices.length < period + 1) return 50;
      let gains = 0, losses = 0;
      for (let j = 1; j <= period; j++) {
        const delta = prices[prices.length - j] - prices[prices.length - j - 1];
        if (delta > 0) gains += delta;
        else losses -= delta;
      }
      const rs = losses === 0 ? 100 : gains / losses;
      return 100 - (100 / (1 + rs));
    }

    const rsi7 = Math.round(calcRSI(closes, 7) * 10) / 10;
    const rsi14 = Math.round(calcRSI(closes, 14) * 10) / 10;
    const rsi21 = Math.round(calcRSI(closes, 21) * 10) / 10;

    // MACD (multiple settings)
    function calcEMA(prices, period) {
      const alpha = 2 / (period + 1);
      let ema = prices.slice(0, period).reduce((a, b) => a + b, 0) / period;
      for (let j = period; j < prices.length; j++) {
        ema = prices[j] * alpha + ema * (1 - alpha);
      }
      return ema;
    }

    const ema12 = calcEMA(closes, 12);
    const ema26 = calcEMA(closes, 26);
    const macdLine = ema12 - ema26;

    const macdSignal = calcEMA(closes.slice(-26).concat([ema12]).map((_, idx, arr) => {
      if (idx < 12) return arr[idx];
      return calcEMA(closes.slice(0, idx + 1), 12) - calcEMA(closes.slice(0, idx + 1), 26);
    }), 9);

    const macdHist = macdLine - macdSignal;

    // MACD 8/21/5
    const ema8 = calcEMA(closes, 8);
    const ema21 = calcEMA(closes, 21);
    const macdLine2 = ema8 - ema21;
    const macdHist2 = macdLine2 - (macdLine2 * 0.8);

    // Moving Averages
    const ma20 = closes.slice(-20).reduce((a, b) => a + b, 0) / 20;
    const ma50 = closes.slice(-50).reduce((a, b) => a + b, 0) / Math.min(closes.length, 50);
    const ma200 = closes.length >= 200 ? closes.slice(-200).reduce((a, b) => a + b, 0) / 200 : price;

    // Bollinger Bands (multiple std devs)
    function calcBB(prices, period, stdDev) {
      const mid = prices.slice(-period).reduce((a, b) => a + b, 0) / period;
      const variance = prices.slice(-period).reduce((a, b) => a + Math.pow(b - mid, 2), 0) / period;
      const std = Math.sqrt(variance);
      return { upper: mid + stdDev * std, lower: mid - stdDev * std, mid };
    }

    const bb2 = calcBB(closes, 20, 2.0);
    const bb15 = calcBB(closes, 20, 1.5);
    const bb25 = calcBB(closes, 20, 2.5);

    // Volume analysis
    const avgVolume = volumes.slice(-20).reduce((a, b) => a + b, 0) / 20;
    const currentVolume = volumes[volumes.length - 1] || 0;
    const volumeRatio = avgVolume > 0 ? currentVolume / avgVolume : 1;

    // Stochastic Oscillator
    function calcStoch(highs, lows, closes, kPeriod, dPeriod) {
      const k = [];
      for (let j = kPeriod - 1; j < closes.length; j++) {
        const highest = Math.max(...highs.slice(j - kPeriod + 1, j + 1));
        const lowest = Math.min(...lows.slice(j - kPeriod + 1, j + 1));
        k.push(highest !== lowest ? 100 * (closes[j] - lowest) / (highest - lowest) : 50);
      }
      const kVal = k[k.length - 1];
      const dVal = k.slice(-dPeriod).reduce((a, b) => a + b, 0) / Math.min(k.length, dPeriod);
      return { k: kVal, d: dVal };
    }

    const stoch = calcStoch(highs, lows, closes, 14, 3);

    // ATR (Average True Range)
    function calcATR(highs, lows, closes, period) {
      let tr = [];
      for (let j = 1; j < closes.length; j++) {
        tr.push(Math.max(
          highs[j] - lows[j],
          Math.abs(highs[j] - closes[j - 1]),
          Math.abs(lows[j] - closes[j - 1])
        ));
      }
      return tr.slice(-period).reduce((a, b) => a + b, 0) / period;
    }

    const atr = calcATR(highs, lows, closes, 14);

    // ADX (Average Directional Index) - simplified
    function calcADX(highs, lows, closes, period) {
      let plusDM = 0, minusDM = 0, trSum = 0;
      for (let j = 1; j <= period && j < closes.length; j++) {
        const tr = Math.max(highs[j] - lows[j], Math.abs(highs[j] - closes[j-1]), Math.abs(lows[j] - closes[j-1]));
        trSum += tr;
        if (highs[j] - highs[j-1] > lows[j-1] - lows[j]) plusDM += Math.max(0, highs[j] - highs[j-1]);
        if (lows[j-1] - lows[j] > highs[j] - highs[j-1]) minusDM += Math.max(0, lows[j-1] - lows[j]);
      }
      const plusDI = trSum > 0 ? 100 * plusDM / trSum : 0;
      const minusDI = trSum > 0 ? 100 * minusDM / trSum : 0;
      const dx = plusDI + minusDI > 0 ? 100 * Math.abs(plusDI - minusDI) / (plusDI + minusDI) : 0;
      return dx;
    }

    const adx = calcADX(highs, lows, closes, 14);

    // OBV (On-Balance Volume)
    function calcOBV(closes, volumes) {
      let obv = 0;
      for (let j = 1; j < closes.length; j++) {
        if (closes[j] > closes[j-1]) obv += volumes[j];
        else if (closes[j] < closes[j-1]) obv -= volumes[j];
      }
      return obv;
    }

    const obv = calcOBV(closes, volumes);
    const obvSma = obv / closes.length;
    const obvTrend = obv > obvSma ? 'bullish' : 'bearish';

    // Price changes
    const weekChange = ((price - closes[closes.length - 5]) / closes[closes.length - 5] * 100);
    const monthChange = ((price - closes[closes.length - 21]) / closes[closes.length - 21] * 100);

    // Momentum
    const momentum5 = ((price - closes[closes.length - 5]) / closes[closes.length - 5] * 100);
    const momentum10 = ((price - closes[closes.length - 10]) / closes[closes.length - 10] * 100);
    const momentum21 = ((price - closes[closes.length - 21]) / closes[closes.length - 21] * 100);

    results.push({
      json: {
        type: 'stock',
        symbol,
        current_price: Math.round(price * 100) / 100,
        high_30d: Math.round(high30 * 100) / 100,
        low_30d: Math.round(low30 * 100) / 100,

        // RSI
        rsi_7: rsi7,
        rsi_14: rsi14,
        rsi_21: rsi21,

        // MACD
        macd_line: Math.round(macdLine * 100) / 100,
        macd_signal: Math.round(macdSignal * 100) / 100,
        macd_histogram: Math.round(macdHist * 100) / 100,
        macd_8_21_line: Math.round(macdLine2 * 100) / 100,
        macd_8_21_hist: Math.round(macdHist2 * 100) / 100,

        // Moving Averages
        ma_20: Math.round(ma20 * 100) / 100,
        ma_50: Math.round(ma50 * 100) / 100,
        ma_200: Math.round(ma200 * 100) / 100,

        // Bollinger Bands
        bb_upper: Math.round(bb2.upper * 100) / 100,
        bb_lower: Math.round(bb2.lower * 100) / 100,
        bb_middle: Math.round(bb2.mid * 100) / 100,
        bb_upper_15: Math.round(bb15.upper * 100) / 100,
        bb_lower_15: Math.round(bb15.lower * 100) / 100,
        bb_upper_25: Math.round(bb25.upper * 100) / 100,
        bb_lower_25: Math.round(bb25.lower * 100) / 100,
        bb_width: Math.round((bb2.upper - bb2.lower) * 100) / 100,
        bb_position: Math.round((price - bb2.lower) / (bb2.upper - bb2.lower) * 100),

        // Volume
        avg_volume: Math.round(avgVolume),
        volume_ratio: Math.round(volumeRatio * 100) / 100,

        // Stochastic
        stoch_k: Math.round(stoch.k * 10) / 10,
        stoch_d: Math.round(stoch.d * 10) / 10,

        // ATR & ADX
        atr: Math.round(atr * 100) / 100,
        adx: Math.round(adx * 10) / 10,

        // OBV
        obv_trend: obvTrend,

        // Momentum
        momentum_5: Math.round(momentum5 * 100) / 100,
        momentum_10: Math.round(momentum10 * 100) / 100,
        momentum_21: Math.round(momentum21 * 100) / 100,

        // Price changes
        week_change_pct: Math.round(weekChange * 100) / 100,
        month_change_pct: Math.round(monthChange * 100) / 100
      }
    });
  } catch (e) {
    console.error('Stock parse error:', e.message);
  }
}

if (results.length === 0) {
  results.push({ json: { type: 'none', symbol: 'ERROR', error: 'No stock data available' } });
}

return results;

// Real RSI, MACD, Bollinger Bands from OHLC data (matching stock calculations)
const items = $input.all();
const ids = $('Split Crypto').all();
const results = [];

function calcRSI(prices, period) {
  if (prices.length < period + 1) return 50;
  let gains = 0, losses = 0;
  for (let j = 1; j <= period; j++) {
    const delta = prices[prices.length - j] - prices[prices.length - j - 1];
    if (delta > 0) gains += delta;
    else losses -= delta;
  }
  const rs = losses === 0 ? 100 : gains / losses;
  return 100 - (100 / (1 + rs));
}

function calcEMA(prices, period) {
  const alpha = 2 / (period + 1);
  let ema = prices.slice(0, period).reduce((a, b) => a + b, 0) / period;
  for (let j = period; j < prices.length; j++) {
    ema = prices[j] * alpha + ema * (1 - alpha);
  }
  return ema;
}

function calcBB(prices, period, stdDev) {
  const mid = prices.slice(-period).reduce((a, b) => a + b, 0) / period;
  const variance = prices.slice(-period).reduce((a, b) => a + Math.pow(b - mid, 2), 0) / period;
  const std = Math.sqrt(variance);
  return { upper: mid + stdDev * std, lower: mid - stdDev * std, mid };
}

for (let i = 0; i < items.length; i++) {
  try {
    const id = ids[i]?.json?.id;
    const ohlc = items[i].json;

    if (!id || !Array.isArray(ohlc) || ohlc.length < 30) {
      console.log('Insufficient OHLC data for:', id);
      continue;
    }

    // OHLC format: [timestamp, open, high, low, close]
    const closes = ohlc.map(c => c[4]).filter(c => c != null);
    const highs = ohlc.map(c => c[2]).filter(c => c != null);
    const lows = ohlc.map(c => c[3]).filter(c => c != null);

    if (closes.length < 30) continue;

    const price = closes[closes.length - 1];
    const high90 = Math.max(...closes.slice(-90));
    const low90 = Math.min(...closes.slice(-90));

    // RSI variants
    const rsi7 = Math.round(calcRSI(closes, 7) * 10) / 10;
    const rsi14 = Math.round(calcRSI(closes, 14) * 10) / 10;
    const rsi21 = Math.round(calcRSI(closes, 21) * 10) / 10;

    // MACD
    const ema12 = calcEMA(closes, 12);
    const ema26 = calcEMA(closes, 26);
    const macdLine = ema12 - ema26;
    const macdSignalVals = [];
    for (let j = 9; j <= closes.length; j++) {
      const slice = closes.slice(0, j);
      const e12 = calcEMA(slice, 12);
      const e26 = calcEMA(slice, 26);
      macdSignalVals.push(e12 - e26);
    }
    const macdSignal = calcEMA(macdSignalVals, 9);
    const macdHist = macdLine - macdSignal;

    // MACD 8/21/5
    const ema8 = calcEMA(closes, 8);
    const ema21 = calcEMA(closes, 21);
    const macdLine2 = ema8 - ema21;
    const macdHist2 = macdLine2 - (macdLine2 * 0.8);

    // Moving Averages
    const ma20 = closes.slice(-20).reduce((a, b) => a + b, 0) / 20;
    const ma50 = closes.slice(-50).reduce((a, b) => a + b, 0) / Math.min(closes.length, 50);
    const ma200 = closes.length >= 200 ? closes.slice(-200).reduce((a, b) => a + b, 0) / 200 : price;

    // Bollinger Bands
    const bb2 = calcBB(closes, 20, 2.0);
    const bb15 = calcBB(closes, 20, 1.5);
    const bb25 = calcBB(closes, 20, 2.5);
    const bbPosition = Math.round((price - bb2.lower) / (bb2.upper - bb2.lower) * 100);

    // Price changes
    const weekChange = ((price - closes[closes.length - 5]) / closes[closes.length - 5] * 100);
    const monthChange = ((price - closes[closes.length - 21]) / closes[closes.length - 21] * 100);
    const momentum21 = ((price - closes[closes.length - 21]) / closes[closes.length - 21] * 100);

    results.push({
      json: {
        type: 'crypto',
        id,
        symbol: id.toUpperCase(),
        current_price: Math.round(price * 100) / 100,
        high_90d: Math.round(high90 * 100) / 100,
        low_90d: Math.round(low90 * 100) / 100,

        // RSI (same as stocks)
        rsi_7: rsi7,
        rsi_14: rsi14,
        rsi_21: rsi21,

        // MACD (same as stocks)
        macd_line: Math.round(macdLine * 100) / 100,
        macd_signal: Math.round(macdSignal * 100) / 100,
        macd_histogram: Math.round(macdHist * 100) / 100,
        macd_8_21_line: Math.round(macdLine2 * 100) / 100,
        macd_8_21_hist: Math.round(macdHist2 * 100) / 100,

        // Moving Averages
        ma_20: Math.round(ma20 * 100) / 100,
        ma_50: Math.round(ma50 * 100) / 100,
        ma_200: Math.round(ma200 * 100) / 100,

        // Bollinger Bands
        bb_upper: Math.round(bb2.upper * 100) / 100,
        bb_lower: Math.round(bb2.lower * 100) / 100,
        bb_middle: Math.round(bb2.mid * 100) / 100,
        bb_upper_15: Math.round(bb15.upper * 100) / 100,
        bb_lower_15: Math.round(bb15.lower * 100) / 100,
        bb_upper_25: Math.round(bb25.upper * 100) / 100,
        bb_lower_25: Math.round(bb25.lower * 100) / 100,
        bb_position: bbPosition,

        // Price changes
        week_change_pct: Math.round(weekChange * 100) / 100,
        month_change_pct: Math.round(monthChange * 100) / 100,
        momentum_21: Math.round(momentum21 * 100) / 100
      }
    });
  } catch (e) {
    console.error('Crypto parse error:', e.message);
  }
}

return results.length ? results : [{ json: { type: 'none', symbol: 'ERROR', error: 'No crypto data available' } }];

const allData = $input.all();
const stocks = allData.filter(d => d.json.type === 'stock').map(d => d.json);
const crypto = allData.filter(d => d.json.type === 'crypto').map(d => d.json);
const positions = $('Prepare Input').first().json.positions;
const timestamp = $('Prepare Input').first().json.timestamp;
const timeLabel = $('Prepare Input').first().json.timeLabel;

// Load optimized parameters from file
let optimizedParams = {
  thresholds: {
    rsi_oversold: 30,
    rsi_overbought: 70,
    volume_spike_multiplier: 1.5,
    macd_histogram_threshold: 0.15
  },
  confidence_weights: {
    rsi: 0.40,
    macd: 0.20,
    volume: 0.15,
    momentum: 0.15,
    bollinger: 0.10
  },
  risk_parameters: {
    stop_loss_pct: 6.0,
    take_profit_pct: 8.0,
    trailing_stop_pct: 4.0
  }
};

try {
  const patternsRaw = $input.first().binary?.data?.data;
  if (patternsRaw) {
    const patterns = JSON.parse(Buffer.from(patternsRaw, 'base64').toString('utf-8'));
    if (patterns.threshold_adjustments) optimizedParams.thresholds = patterns.threshold_adjustments;
    if (patterns.confidence_weights) optimizedParams.confidence_weights = patterns.confidence_weights;
    if (patterns.risk_parameters) optimizedParams.risk_parameters = patterns.risk_parameters;
  }
} catch (e) {
  console.log('Using default parameters');
}

// Build comprehensive context for AI
const lines = [];
lines.push('=== MARKET DATA ===');
lines.push('Timestamp: ' + timestamp);
lines.push('Session: ' + timeLabel.toUpperCase());
lines.push('');
lines.push('=== OPTIMIZED PARAMETERS (Walk-Forward Validated) ===');
lines.push('RSI Oversold: ' + optimizedParams.thresholds.rsi_oversold);
lines.push('RSI Overbought: ' + optimizedParams.thresholds.rsi_overbought);
lines.push('Volume Spike: ' + optimizedParams.thresholds.volume_spike_multiplier + 'x');
lines.push('Stop Loss: ' + optimizedParams.risk_parameters.stop_loss_pct + '%');
lines.push('Take Profit: ' + optimizedParams.risk_parameters.take_profit_pct + '%');
lines.push('');
lines.push('Confidence Weights:');
lines.push('  RSI: ' + (optimizedParams.confidence_weights.rsi * 100) + '%');
lines.push('  MACD: ' + (optimizedParams.confidence_weights.macd * 100) + '%');
lines.push('  Bollinger: ' + (optimizedParams.confidence_weights.bollinger * 100) + '%');
lines.push('  Momentum: ' + (optimizedParams.confidence_weights.momentum * 100) + '%');
lines.push('  Volume: ' + (optimizedParams.confidence_weights.volume * 100) + '%');
lines.push('');

if (stocks.length > 0) {
  lines.push('--- STOCKS ---');
  for (const s of stocks) {
    lines.push(s.symbol + ': $' + s.current_price);
    lines.push('  RSI: 7=' + s.rsi_7 + ' | 14=' + s.rsi_14 + ' | 21=' + s.rsi_21);
    lines.push('  MACD: ' + s.macd_line + ' (signal: ' + s.macd_signal + ', hist: ' + s.macd_histogram + ')');
    lines.push('  MACD(8/21): ' + s.macd_8_21_line + ' (hist: ' + s.macd_8_21_hist + ')');
    lines.push('  MA: 20d=' + s.ma_20 + ', 50d=' + s.ma_50 + ', 200d=' + s.ma_200);
    lines.push('  BB: $' + s.bb_lower + ' - $' + s.bb_upper + ' (pos: ' + s.bb_position + '%)');
    lines.push('  Stochastic: K=' + s.stoch_k + ', D=' + s.stoch_d);
    lines.push('  ATR: ' + s.atr + ', ADX: ' + s.adx);
    lines.push('  OBV: ' + s.obv_trend);
    lines.push('  Momentum: 5d=' + s.momentum_5 + '%, 10d=' + s.momentum_10 + '%, 21d=' + s.momentum_21 + '%');
    lines.push('  Volume: ' + s.volume_ratio + 'x avg');
    lines.push('  7d: ' + (s.week_change_pct > 0 ? '+' : '') + s.week_change_pct + '%');

    // Signal hints
    const hints = [];
    if (s.rsi_14 < optimizedParams.thresholds.rsi_oversold) hints.push('RSI OVERSOLD');
    if (s.rsi_14 > optimizedParams.thresholds.rsi_overbought) hints.push('RSI OVERBOUGHT');
    if (s.volume_ratio > optimizedParams.thresholds.volume_spike_multiplier) hints.push('VOLUME SPIKE');
    if (s.macd_histogram > optimizedParams.thresholds.macd_histogram_threshold) hints.push('MACD BULLISH');
    if (s.macd_histogram < -optimizedParams.thresholds.macd_histogram_threshold) hints.push('MACD BEARISH');
    if (s.current_price < s.bb_lower) hints.push('BELOW BB LOWER');
    if (s.current_price > s.bb_upper) hints.push('ABOVE BB UPPER');
    if (s.stoch_k < 20 && s.stoch_k > s.stoch_d) hints.push('STOCH BULLISH CROSS');
    if (s.stoch_k > 80 && s.stoch_k < s.stoch_d) hints.push('STOCH BEARISH CROSS');
    if (s.adx > 25) hints.push('STRONG TREND (ADX ' + s.adx + ')');
    if (hints.length > 0) lines.push('  SIGNALS: ' + hints.join(', '));
  }
  lines.push('');
}

if (crypto.length > 0) {
  lines.push('--- CRYPTO ---');
  for (const c of crypto) {
    lines.push(c.symbol + ': $' + c.current_price);
    lines.push('  RSI: ' + c.rsi_14_approx + ' | 7d: ' + (c.week_change_pct > 0 ? '+' : '') + c.week_change_pct + '%');
  }
  lines.push('');
}

if (Object.keys(positions).length > 0) {
  lines.push('--- POSITIONS ---');
  for (const [id, pos] of Object.entries(positions)) {
    lines.push(pos.symbol + ': Entry $' + pos.entry_price + ' | Stop $' + pos.stop_loss + ' | Target $' + pos.take_profit);
  }
  lines.push('');
}

return [{
  json: {
    timestamp,
    timeLabel,
    humanSummary: lines.join('\n'),
    stocks,
    crypto,
    positions,
    optimizedParams,
    analysisData: { stocks, crypto, positions, timestamp, time_label: timeLabel }
  }
}];

// Build comprehensive context for AI with null checks and error handling
const allData = $input.all();
const stocks = allData.filter(d => d.json.type === 'stock' && !d.json.error).map(d => d.json);
const crypto = allData.filter(d => d.json.type === 'crypto' && !d.json.error).map(d => d.json);
const positions = $('Prepare Input').first().json.positions || {};
const timestamp = $('Prepare Input').first().json.timestamp;
const timeLabel = $('Prepare Input').first().json.timeLabel;

// Log errors for failed fetches
