const results = [];

// Load optimized parameters
let optimizedParams = {
  rsi_period: 14,
  rsi_oversold: 30,
  rsi_overbought: 70,
  bb_std_dev: 2.0,
  volume_threshold: 1.5,
  macd_fast: 12,
