for (let i = 0; i < items.length; i++) {
  try {
    if (items[i].json.error || items[i].json.code) {
      console.log('API error for', symbols[i]?.json?.symbol, ':', items[i].json.message || 'Unknown error');
      continue;
    }

    const data = items[i].json.chart?.result?.[0];
    const symbol = symbols[i]?.json?.symbol;
    if (!data || !symbol) continue;

    const quote = data.indicators?.quote?.[0];
    const closes = (quote?.close || []).filter(c => c != null);
    const highs = (quote?.high || []).filter(h => h != null);
    const lows = (quote?.low || []).filter(l => l != null);
    const volumes = (quote?.volume || []).filter(v => v != null);

    if (closes.length < 30) {
      console.log('Insufficient data for:', symbol);
      continue;
    }

    const price = closes[closes.length - 1];
    const high30 = Math.max(...closes.slice(-30));
    const low30 = Math.min(...closes.slice(-30));

    // RSI variants (7, 14, 21)
    function calcRSI(prices, period) {
      if (prices.length < period + 1) return 50;
      let gains = 0, losses = 0;
      for (let j = 1; j <= period; j++) {
        const delta = prices[prices.length - j] - prices[prices.length - j - 1];
        if (delta > 0) gains += delta;
        else losses -= delta;
      }
      const rs = losses === 0 ? 100 : gains / losses;
      return 100 - (100 / (1 + rs));
    }

    const rsi7 = Math.round(calcRSI(closes, 7) * 10) / 10;
    const rsi14 = Math.round(calcRSI(closes, 14) * 10) / 10;
    const rsi21 = Math.round(calcRSI(closes, 21) * 10) / 10;

    // MACD (multiple settings)
    function calcEMA(prices, period) {
      const alpha = 2 / (period + 1);
      let ema = prices.slice(0, period).reduce((a, b) => a + b, 0) / period;
      for (let j = period; j < prices.length; j++) {
        ema = prices[j] * alpha + ema * (1 - alpha);
      }
      return ema;
    }

    const ema12 = calcEMA(closes, 12);
    const ema26 = calcEMA(closes, 26);
    const macdLine = ema12 - ema26;

    const macdSignal = calcEMA(closes.slice(-26).concat([ema12]).map((_, idx, arr) => {
      if (idx < 12) return arr[idx];
      return calcEMA(closes.slice(0, idx + 1), 12) - calcEMA(closes.slice(0, idx + 1), 26);
    }), 9);

    const macdHist = macdLine - macdSignal;

    // MACD 8/21/5
    const ema8 = calcEMA(closes, 8);
    const ema21 = calcEMA(closes, 21);
    const macdLine2 = ema8 - ema21;
    const macdHist2 = macdLine2 - (macdLine2 * 0.8);

    // Moving Averages
    const ma20 = closes.slice(-20).reduce((a, b) => a + b, 0) / 20;
    const ma50 = closes.slice(-50).reduce((a, b) => a + b, 0) / Math.min(closes.length, 50);
    const ma200 = closes.length >= 200 ? closes.slice(-200).reduce((a, b) => a + b, 0) / 200 : price;

    // Bollinger Bands (multiple std devs)
    function calcBB(prices, period, stdDev) {
      const mid = prices.slice(-period).reduce((a, b) => a + b, 0) / period;
      const variance = prices.slice(-period).reduce((a, b) => a + Math.pow(b - mid, 2), 0) / period;
      const std = Math.sqrt(variance);
      return { upper: mid + stdDev * std, lower: mid - stdDev * std, mid };
    }

    const bb2 = calcBB(closes, 20, 2.0);
    const bb15 = calcBB(closes, 20, 1.5);
    const bb25 = calcBB(closes, 20, 2.5);

    // Volume analysis
    const avgVolume = volumes.slice(-20).reduce((a, b) => a + b, 0) / 20;
    const currentVolume = volumes[volumes.length - 1] || 0;
    const volumeRatio = avgVolume > 0 ? currentVolume / avgVolume : 1;

    // Stochastic Oscillator
    function calcStoch(highs, lows, closes, kPeriod, dPeriod) {
      const k = [];
      for (let j = kPeriod - 1; j < closes.length; j++) {
        const highest = Math.max(...highs.slice(j - kPeriod + 1, j + 1));
        const lowest = Math.min(...lows.slice(j - kPeriod + 1, j + 1));
        k.push(highest !== lowest ? 100 * (closes[j] - lowest) / (highest - lowest) : 50);
      }
      const kVal = k[k.length - 1];
      const dVal = k.slice(-dPeriod).reduce((a, b) => a + b, 0) / Math.min(k.length, dPeriod);
      return { k: kVal, d: dVal };
    }

    const stoch = calcStoch(highs, lows, closes, 14, 3);

    // ATR (Average True Range)
    function calcATR(highs, lows, closes, period) {
      let tr = [];
      for (let j = 1; j < closes.length; j++) {
        tr.push(Math.max(
          highs[j] - lows[j],
          Math.abs(highs[j] - closes[j - 1]),
          Math.abs(lows[j] - closes[j - 1])
        ));
      }
      return tr.slice(-period).reduce((a, b) => a + b, 0) / period;
    }

    const atr = calcATR(highs, lows, closes, 14);

    // ADX (Average Directional Index) - simplified
    function calcADX(highs, lows, closes, period) {
      let plusDM = 0, minusDM = 0, trSum = 0;
      for (let j = 1; j <= period && j < closes.length; j++) {
        const tr = Math.max(highs[j] - lows[j], Math.abs(highs[j] - closes[j-1]), Math.abs(lows[j] - closes[j-1]));
        trSum += tr;
        if (highs[j] - highs[j-1] > lows[j-1] - lows[j]) plusDM += Math.max(0, highs[j] - highs[j-1]);
        if (lows[j-1] - lows[j] > highs[j] - highs[j-1]) minusDM += Math.max(0, lows[j-1] - lows[j]);
      }
      const plusDI = trSum > 0 ? 100 * plusDM / trSum : 0;
      const minusDI = trSum > 0 ? 100 * minusDM / trSum : 0;
      const dx = plusDI + minusDI > 0 ? 100 * Math.abs(plusDI - minusDI) / (plusDI + minusDI) : 0;
      return dx;
    }

    const adx = calcADX(highs, lows, closes, 14);

    // OBV (On-Balance Volume)
    function calcOBV(closes, volumes) {
      let obv = 0;
      for (let j = 1; j < closes.length; j++) {
        if (closes[j] > closes[j-1]) obv += volumes[j];
        else if (closes[j] < closes[j-1]) obv -= volumes[j];
      }
      return obv;
    }

    const obv = calcOBV(closes, volumes);
    const obvSma = obv / closes.length;
    const obvTrend = obv > obvSma ? 'bullish' : 'bearish';

    // Price changes
    const weekChange = ((price - closes[closes.length - 5]) / closes[closes.length - 5] * 100);
    const monthChange = ((price - closes[closes.length - 21]) / closes[closes.length - 21] * 100);

    // Momentum
    const momentum5 = ((price - closes[closes.length - 5]) / closes[closes.length - 5] * 100);
    const momentum10 = ((price - closes[closes.length - 10]) / closes[closes.length - 10] * 100);
    const momentum21 = ((price - closes[closes.length - 21]) / closes[closes.length - 21] * 100);

    results.push({
      json: {
        type: 'stock',
        symbol,
        current_price: Math.round(price * 100) / 100,
        high_30d: Math.round(high30 * 100) / 100,
        low_30d: Math.round(low30 * 100) / 100,

        // RSI
        rsi_7: rsi7,
        rsi_14: rsi14,
        rsi_21: rsi21,

