        macd_8_21_line: Math.round(macdLine2 * 100) / 100,
        macd_8_21_hist: Math.round(macdHist2 * 100) / 100,

        // Moving Averages
        ma_20: Math.round(ma20 * 100) / 100,
        ma_50: Math.round(ma50 * 100) / 100,
        ma_200: Math.round(ma200 * 100) / 100,

        // Bollinger Bands
        bb_upper: Math.round(bb2.upper * 100) / 100,
        bb_lower: Math.round(bb2.lower * 100) / 100,
        bb_middle: Math.round(bb2.mid * 100) / 100,
        bb_upper_15: Math.round(bb15.upper * 100) / 100,
