    if (rsi < 25) {
      confidence += 20;
      reasons.push('RSI extremely oversold (<25)');
    } else if (rsi < thresholds.rsi_oversold) {
      confidence += 10;
      reasons.push('RSI oversold');
    }
  } else if (action === 'sell') {
    if (rsi > 75) {
      confidence += 20;
      reasons.push('RSI extremely overbought (>75)');
    } else if (rsi > thresholds.rsi_overbought) {
      confidence += 10;
      reasons.push('RSI overbought');
    }
  }

  // MACD crossover confirmed (+15)
  const macdHist = data.macd_histogram || 0;
  if (action === 'buy' && macdHist > thresholds.macd_histogram_threshold) {
    confidence += 15;
    reasons.push('MACD strongly bullish');
  } else if (action === 'sell' && macdHist < -thresholds.macd_histogram_threshold) {
    confidence += 15;
    reasons.push('MACD strongly bearish');
  } else if ((action === 'buy' && macdHist > 0) || (action === 'sell' && macdHist < 0)) {
    confidence += 8;
    reasons.push('MACD confirmed');
  }

  // Volume spike (+12)
  if (data.volume_ratio && data.volume_ratio > thresholds.volume_spike_multiplier) {
    confidence += 12;
    reasons.push(`Volume spike (${data.volume_ratio}x)`);
  }

  // Bollinger band touch + reversal (+10)
  const bbPos = data.bb_position || 50;
  if (action === 'buy' && bbPos < 10) {
    confidence += 10;
    reasons.push('Price at BB lower band');
  } else if (action === 'sell' && bbPos > 90) {
    confidence += 10;
    reasons.push('Price at BB upper band');
  }

  // ADX strong trend (+8)
  if (data.adx && data.adx > 25) {
    confidence += 8;
    reasons.push(`Strong trend (ADX ${data.adx})`);
  }

  // Multiple timeframe agreement (+15)
  const rsi7 = data.rsi_7 || 50;
  const rsi21 = data.rsi_21 || 50;
  if (action === 'buy' && rsi7 < rsi && rsi < rsi21 && rsi21 < thresholds.rsi_oversold) {
    confidence += 15;
    reasons.push('Multi-timeframe RSI alignment');
  } else if (action === 'sell' && rsi7 > rsi && rsi > rsi21 && rsi21 > thresholds.rsi_overbought) {
    confidence += 15;
    reasons.push('Multi-timeframe RSI alignment');
  }

  // Subtract for conflicting signals (-10)
  const conflicts = [];
  if (action === 'buy') {
    if (macdHist < -0.1) conflicts.push('MACD bearish');
    if (bbPos > 70) conflicts.push('Near BB upper');
  } else if (action === 'sell') {
    if (macdHist > 0.1) conflicts.push('MACD bullish');
    if (bbPos < 30) conflicts.push('Near BB lower');
  }

  if (conflicts.length > 0) {
    confidence -= 10 * conflicts.length;
    reasons.push(`Conflicting: ${conflicts.join(', ')}`);
  }

  // Cap at 5-95 range
  confidence = Math.max(5, Math.min(95, confidence));

  return { confidence: Math.round(confidence), reasons };
}

// Process signals
const signals = [];

for (const sig of (aiOutput.signals || [])) {
  const stockData = stocks.find(s => s.symbol === sig.symbol);
  const cryptoData = crypto.find(c => c.symbol === sig.symbol || c.id === sig.symbol?.toLowerCase());
  const data = stockData || cryptoData;

  const { confidence, reasons } = calcConfidence(data, sig.action, optimizedParams.thresholds);

  signals.push({
    ...sig,
    confidence,
    tech_reasons: reasons,
    price: data?.current_price
  });
}

// Position alerts (keep existing logic)
for (const [id, pos] of Object.entries(positions)) {
  const stockData = stocks.find(s => s.symbol?.toLowerCase() === pos.symbol?.toLowerCase());
  const cryptoData = crypto.find(c => c.id?.toLowerCase() === pos.symbol?.toLowerCase());
  const data = stockData || cryptoData;

  if (!data) continue;

  const price = data.current_price;
  const stopDist = (price - pos.stop_loss) / pos.stop_loss * 100;
  const targetDist = (pos.take_profit - price) / price * 100;

  if (stopDist < 3) {
    signals.push({
      symbol: pos.symbol,
      action: 'sell',
      confidence: Math.min(95, 90 + Math.round((3 - stopDist) * 3)),
      reason: `Position near stop loss (${stopDist.toFixed(1)}% away)`,
      urgency: 'critical',
      tech_reasons: ['Stop loss proximity'],
      position_id: id,
      price
    });
  }

  if (targetDist < 5) {
    signals.push({
      symbol: pos.symbol,
      action: 'sell',
      confidence: Math.min(95, 70 + Math.round((5 - targetDist) * 2)),
      reason: `Position near target (${targetDist.toFixed(1)}% away)`,
      urgency: 'high',
      tech_reasons: ['Take profit proximity'],
      position_id: id,
      price
    });
  }
}

signals.sort((a, b) => b.confidence - a.confidence);

return [{
  json: {
    timestamp,
    market_overview: aiOutput.market_overview,
    signals,
    recommendations: aiOutput.recommendations,
    risk_assessment: aiOutput.risk_assessment,
    stocks,
    crypto,
    positions,
    optimizedParams,
    confidenceDistribution: {
      min: signals.length ? Math.min(...signals.map(s => s.confidence)) : 0,
      max: signals.length ? Math.max(...signals.map(s => s.confidence)) : 0,
      avg: signals.length ? Math.round(signals.reduce((a, b) => a + b.confidence, 0) / signals.length) : 0
    }
  }
}];
